import{_ as e,o as s,c as o,ag as i}from"./chunks/framework.CTpQozEL.js";const g=JSON.parse('{"title":"원격 제어","description":"SSH를 통해 원격 OpenClaw 게이트웨이를 제어하는 macOS 앱 흐름","frontmatter":{"title":"원격 제어","description":"SSH를 통해 원격 OpenClaw 게이트웨이를 제어하는 macOS 앱 흐름"},"headers":[],"relativePath":"platforms/mac/remote.md","filePath":"platforms/mac/remote.md","lastUpdated":null}'),t={name:"platforms/mac/remote.md"};function l(n,a,r,c,h,d){return s(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="원격-openclaw-macos-⇄-원격-호스트" tabindex="-1">원격 OpenClaw (macOS ⇄ 원격 호스트) <a class="header-anchor" href="#원격-openclaw-macos-⇄-원격-호스트" aria-label="Permalink to &quot;원격 OpenClaw (macOS ⇄ 원격 호스트)&quot;">​</a></h1><p>이 흐름을 통해 macOS 앱이 다른 호스트 (데스크탑/서버)에서 실행 중인 OpenClaw 게이트웨이의 완전한 원격 제어 역할을 할 수 있습니다. 앱의 <strong>Remote over SSH</strong> (원격 실행) 기능입니다. 상태 확인, Voice Wake 전달, Web Chat을 포함한 모든 기능이 _설정 → General_의 동일한 원격 SSH 구성을 재사용합니다.</p><h2 id="모드" tabindex="-1">모드 <a class="header-anchor" href="#모드" aria-label="Permalink to &quot;모드&quot;">​</a></h2><ul><li><strong>로컬 (이 Mac)</strong>: 모든 것이 노트북에서 실행됩니다. SSH 관여 없음.</li><li><strong>Remote over SSH (기본값)</strong>: OpenClaw 명령이 원격 호스트에서 실행됩니다. mac 앱은 <code>-o BatchMode</code>와 선택한 ID/키 및 로컬 포트 포워딩으로 SSH 연결을 엽니다.</li><li><strong>원격 직접 (ws/wss)</strong>: SSH 터널 없음. mac 앱이 게이트웨이 URL에 직접 연결합니다 (예: Tailscale Serve 또는 공용 HTTPS 역방향 프록시를 통해).</li></ul><h2 id="원격-전송" tabindex="-1">원격 전송 <a class="header-anchor" href="#원격-전송" aria-label="Permalink to &quot;원격 전송&quot;">​</a></h2><p>원격 모드는 두 가지 전송을 지원합니다:</p><ul><li><strong>SSH 터널</strong> (기본값): <code>ssh -N -L ...</code>을 사용하여 게이트웨이 포트를 로컬호스트로 전달합니다. 터널이 루프백이므로 게이트웨이는 노드 IP를 <code>127.0.0.1</code>로 봅니다.</li><li><strong>직접 (ws/wss)</strong>: 게이트웨이 URL에 바로 연결합니다. 게이트웨이는 실제 클라이언트 IP를 봅니다.</li></ul><h2 id="원격-호스트의-사전-요구-사항" tabindex="-1">원격 호스트의 사전 요구 사항 <a class="header-anchor" href="#원격-호스트의-사전-요구-사항" aria-label="Permalink to &quot;원격 호스트의 사전 요구 사항&quot;">​</a></h2><ol><li>Node + pnpm을 설치하고 OpenClaw CLI를 빌드/설치합니다 (<code>pnpm install &amp;&amp; pnpm build &amp;&amp; pnpm link --global</code>).</li><li>비대화형 쉘의 PATH에 <code>openclaw</code>가 있는지 확인합니다 (필요한 경우 <code>/usr/local/bin</code> 또는 <code>/opt/homebrew/bin</code>에 심링크).</li><li>키 인증으로 SSH를 엽니다. LAN 외부에서 안정적인 도달 가능성을 위해 <strong>Tailscale</strong> IP를 권장합니다.</li></ol><h2 id="macos-앱-설정" tabindex="-1">macOS 앱 설정 <a class="header-anchor" href="#macos-앱-설정" aria-label="Permalink to &quot;macOS 앱 설정&quot;">​</a></h2><ol><li>_설정 → General_을 엽니다.</li><li><strong>OpenClaw runs</strong> 아래에서 <strong>Remote over SSH</strong>를 선택하고 다음을 설정합니다: <ul><li><strong>전송</strong>: <strong>SSH tunnel</strong> 또는 <strong>Direct (ws/wss)</strong>.</li><li><strong>SSH 대상</strong>: <code>user@host</code> (선택적 <code>:port</code>). <ul><li>게이트웨이가 동일 LAN에 있고 Bonjour를 광고하는 경우 검색된 목록에서 선택하면 이 필드가 자동으로 채워집니다.</li></ul></li><li><strong>게이트웨이 URL</strong> (직접만): <code>wss://gateway.example.ts.net</code> (또는 로컬/LAN의 경우 <code>ws://...</code>).</li><li><strong>ID 파일</strong> (고급): 키 경로.</li><li><strong>프로젝트 루트</strong> (고급): 명령에 사용되는 원격 체크아웃 경로.</li><li><strong>CLI 경로</strong> (고급): 실행 가능한 <code>openclaw</code> 진입점/바이너리의 선택적 경로 (광고된 경우 자동 채워짐).</li></ul></li><li><strong>Test remote</strong>를 클릭합니다. 성공은 원격 <code>openclaw status --json</code>이 올바르게 실행됨을 나타냅니다. 실패는 보통 PATH/CLI 문제를 의미합니다. exit 127은 원격에서 CLI를 찾을 수 없음을 의미합니다.</li><li>상태 확인과 Web Chat이 이제 이 SSH 터널을 통해 자동으로 실행됩니다.</li></ol><h2 id="web-chat" tabindex="-1">Web Chat <a class="header-anchor" href="#web-chat" aria-label="Permalink to &quot;Web Chat&quot;">​</a></h2><ul><li><strong>SSH 터널</strong>: Web Chat이 전달된 WebSocket 제어 포트 (기본값 18789)를 통해 게이트웨이에 연결합니다.</li><li><strong>직접 (ws/wss)</strong>: Web Chat이 구성된 게이트웨이 URL에 바로 연결합니다.</li><li>더 이상 별도의 WebChat HTTP 서버가 없습니다.</li></ul><h2 id="권한" tabindex="-1">권한 <a class="header-anchor" href="#권한" aria-label="Permalink to &quot;권한&quot;">​</a></h2><ul><li>원격 호스트에는 로컬과 동일한 TCC 승인이 필요합니다 (자동화, 접근성, 화면 녹화, 마이크, 음성 인식, 알림). 해당 머신에서 온보딩을 실행하여 한 번 부여하십시오.</li><li>노드는 <code>node.list</code> / <code>node.describe</code>를 통해 권한 상태를 광고하므로 에이전트가 무엇이 허용되는지 알 수 있습니다.</li></ul><h2 id="보안-참고-사항" tabindex="-1">보안 참고 사항 <a class="header-anchor" href="#보안-참고-사항" aria-label="Permalink to &quot;보안 참고 사항&quot;">​</a></h2><ul><li>원격 호스트에서 루프백 바인드를 선호하고 SSH 또는 Tailscale을 통해 연결하십시오.</li><li>SSH 터널링은 엄격한 호스트 키 확인을 사용합니다. <code>~/.ssh/known_hosts</code>에 존재하도록 먼저 호스트 키를 신뢰하십시오.</li><li>게이트웨이를 루프백이 아닌 인터페이스에 바인딩하는 경우 유효한 게이트웨이 인증이 필요합니다: 토큰, 비밀번호, 또는 <code>gateway.auth.mode: &quot;trusted-proxy&quot;</code>가 있는 ID 인식 역방향 프록시.</li><li><a href="/openclaw-docs-ko/gateway/security">보안</a> 및 <a href="/openclaw-docs-ko/gateway/tailscale">Tailscale</a>을 참조하십시오.</li></ul><h2 id="whatsapp-로그인-흐름-원격" tabindex="-1">WhatsApp 로그인 흐름 (원격) <a class="header-anchor" href="#whatsapp-로그인-흐름-원격" aria-label="Permalink to &quot;WhatsApp 로그인 흐름 (원격)&quot;">​</a></h2><ul><li><strong>원격 호스트에서</strong> <code>openclaw channels login --verbose</code>를 실행합니다. 전화기의 WhatsApp으로 QR을 스캔합니다.</li><li>인증이 만료되면 해당 호스트에서 로그인을 다시 실행합니다. 상태 확인이 링크 문제를 표시합니다.</li></ul><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><ul><li><strong>exit 127 / not found</strong>: 비로그인 쉘의 PATH에 <code>openclaw</code>가 없습니다. <code>/etc/paths</code>, 쉘 rc에 추가하거나 <code>/usr/local/bin</code>/<code>/opt/homebrew/bin</code>에 심링크하십시오.</li><li><strong>상태 프로브 실패</strong>: SSH 도달 가능성, PATH, Baileys 로그인 여부 (<code>openclaw status --json</code>)를 확인하십시오.</li><li><strong>Web Chat 멈춤</strong>: 게이트웨이가 원격 호스트에서 실행 중인지, 전달된 포트가 게이트웨이 WS 포트와 일치하는지 확인하십시오. UI는 정상적인 WS 연결이 필요합니다.</li><li><strong>노드 IP가 127.0.0.1 표시</strong>: SSH 터널에서 예상됩니다. 게이트웨이가 실제 클라이언트 IP를 보도록 하려면 <strong>전송</strong>을 **직접 (ws/wss)**로 전환하십시오.</li><li><strong>Voice Wake</strong>: 트리거 구문은 원격 모드에서 자동으로 전달됩니다. 별도의 포워더가 필요하지 않습니다.</li></ul><h2 id="알림-소리" tabindex="-1">알림 소리 <a class="header-anchor" href="#알림-소리" aria-label="Permalink to &quot;알림 소리&quot;">​</a></h2><p>스크립트에서 <code>openclaw</code>와 <code>node.invoke</code>를 사용하여 알림당 소리를 선택합니다. 예:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> notify</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">--title</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Ping&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --body</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Remote gateway ready&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --sound</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Glass</span></span></code></pre></div><p>앱에 더 이상 전역 &quot;기본 소리&quot; 토글이 없습니다. 발신자가 요청당 소리 (또는 없음)를 선택합니다.</p>',25)])])}const k=e(t,[["render",l]]);export{g as __pageData,k as default};
